// // This comment suggests that the counter decrements on the rising edge of the clock and resets to 1 when the reset signal is low.
module counter_4bit(
    input wire CLK,
    input wire RST,
    output reg [3:0] Q
    );

always @(posedge CLK) begin
    if (RST)
        Q <= 4'b0;
    else
        Q <= Q + 1;
end

endmodule
